#!/usr/bin/env node
/**
 * Build latest.json manifest for tauri-plugin-updater from signed installer files.
 *
 * Reads .sig files (generated by `tauri signer sign`) alongside each installer,
 * extracts the minisign signature, and assembles the updater manifest.
 *
 * Usage:
 *   node scripts/make-latest-json.mjs <version> <notes-json> <release-dir> <output-file>
 *
 * Example:
 *   NOTES=$(jq -Rs '.' changelog.md)
 *   node scripts/make-latest-json.mjs "v1.2.1" "$NOTES" ./release/ latest.json
 */

import { readFileSync, readdirSync, writeFileSync } from 'node:fs';
import { resolve, basename } from 'node:path';

const version = process.argv[2];
const notesJson = process.argv[3]; // JSON-stringified changelog
const releaseDir = process.argv[4] || './release';
const outputFile = process.argv[5] || 'latest.json';

if (!version || !notesJson) {
  console.error('Usage: node scripts/make-latest-json.mjs <version> <notes-json> <release-dir> <output-file>');
  process.exit(1);
}

// Parse notes (coming from jq -Rs, it's a JSON string like "### Added\n- ...")
let notes;
try {
  notes = JSON.parse(notesJson);
} catch {
  notes = notesJson;
}

// Platform detection by file extension
function detectPlatform(filename) {
  const lower = filename.toLowerCase();
  if (lower.endsWith('.msi') || lower.endsWith('.exe')) return 'windows-x86_64';
  if (lower.endsWith('.dmg')) return 'darwin-x86_64';
  if (lower.endsWith('.appimage') || lower.endsWith('.deb')) return 'linux-x86_64';
  return null;
}

// Extract signature from .sig file (minisign format)
function extractSignature(sigFile) {
  try {
    const content = readFileSync(sigFile, 'utf-8');
    const lines = content.trim().split('\n');
    // Minisign format:
    //   untrusted comment: ...
    //   <base64-signature>
    //   <base64-trusted-comment>
    // The signature is the second non-empty line (or first base64 line)
    for (const line of lines) {
      const trimmed = line.trim();
      if (!trimmed) continue;
      if (trimmed.startsWith('untrusted') || trimmed.startsWith('Trusted')) continue;
      if (trimmed.startsWith('RW')) return trimmed; // minisign signature starts with RW
    }
    // Fallback: return second line
    const base64Lines = lines.filter(l => l.trim() && !l.trim().startsWith('untrusted') && !l.trim().startsWith('Trusted'));
    return base64Lines[0] || '';
  } catch (e) {
    console.error(`Failed to read signature from ${sigFile}: ${e.message}`);
    return '';
  }
}

// Find all installer files
const files = readdirSync(releaseDir).filter(f => {
  const lower = f.toLowerCase();
  return lower.endsWith('.msi') || lower.endsWith('.exe') ||
         lower.endsWith('.dmg') ||
         lower.endsWith('.appimage') || lower.endsWith('.deb');
});

if (files.length === 0) {
  console.error(`No installer files found in ${releaseDir}`);
  process.exit(1);
}

console.error(`Found ${files.length} installer files`);

// Strip leading 'v' from version for the manifest
const cleanVersion = version.startsWith('v') ? version.slice(1) : version;
const tag = version.startsWith('v') ? version : `v${version}`;

const platforms = {};

for (const file of files) {
  const platform = detectPlatform(file);
  if (!platform) {
    console.error(`Skipping unknown platform for: ${file}`);
    continue;
  }

  const installerPath = resolve(releaseDir, file);
  const sigPath = installerPath + '.sig';

  let signature = '';
  try {
    signature = extractSignature(sigPath);
    console.error(`  ${file} → ${platform}, sig: ${signature ? 'OK' : 'MISSING'}`);
  } catch {
    console.error(`  ${file} → ${platform}, sig: MISSING`);
  }

  const url = `https://github.com/Leaderxin/quant-desktop/releases/download/${tag}/${file}`;

  platforms[platform] = {
    signature,
    url,
  };
}

const manifest = {
  version: cleanVersion,
  notes,
  pub_date: new Date().toISOString(),
  platforms,
};

writeFileSync(outputFile, JSON.stringify(manifest, null, 2) + '\n');
console.error(`latest.json written to ${outputFile}`);
